package com.soumyajit.gradlemc.storage;
import net.minecraft.commands.CommandSourceStack;import net.minecraft.network.chat.Component;import java.io.IOException;
public final class StorageService{private StorageService(){}public static int status(CommandSourceStack s){StorageSummary v=StorageDiagnostics.inspect();send(s,"Storage | game usable="+v.gameUsableBytes()+" | GradleMC usable="+v.outputUsableBytes()+" | reports writable="+v.reportsWritable());send(s,"Reports: "+v.reportFiles()+" files, "+v.reportBytes()+" bytes; oversized="+v.oversizedReports().size()+"; stale temp="+v.staleTemporaryFiles().size());return v.reportsWritable()?1:0;}public static int reports(CommandSourceStack s){StorageSummary v=StorageDiagnostics.inspect();send(s,"Oversized GradleMC reports: "+v.oversizedReports());send(s,"Limitations: "+v.limitations());return 1;}public static int cleanup(CommandSourceStack s,boolean confirm){var candidates=StorageDiagnostics.cleanupCandidates();if(!confirm){send(s,"Cleanup dry-run: "+candidates.size()+" stale GradleMC-owned .tmp files. Run /gradlemc storage cleanup confirm to delete only this validated class of file.");candidates.stream().limit(12).forEach(p->send(s,p.getParent().getFileName()+"/"+p.getFileName()));return 1;}try{int deleted=StorageDiagnostics.deleteCandidates();send(s,"Deleted "+deleted+" validated stale GradleMC-owned temporary files.");return 1;}catch(IOException e){s.sendFailure(Component.literal("Storage cleanup failed: "+e.getMessage()));return 0;}}private static void send(CommandSourceStack s,String m){s.sendSuccess(()->Component.literal(m),false);}}
